draw(A--B--C--A);
draw(X--Y--Z--X);

label("$A$",A,W);
label("$B$",B,NE);
label("$C$",C,SE);
label("$X$",X,E);
label("$Y$",Y,NW);
label("$Z$",Z,SW);

label("$40^\circ$",A+(.2,.06),E);
